    17→function fmtHours(secs: number): string {
    18→  const h = Math.floor(secs / 3600);
    19→  const m = Math.floor((secs % 3600) / 60);
    20→  if (h === 0) return `${m} мин`;
    21→  return m > 0 ? `${h} ч ${m} мин` : `${h} ч`;
    22→}
    23→
    24→function calcSalary(showUps: number, deposits: number, workedSecs: number, rules: CommissionRules): number {
    25→  const over      = deposits > rules.poThreshold;
    26→  const visitRate = over ? rules.perShowUpHigh : rules.perShowUpLow;
    27→  const poRate    = over ? rules.perPoHigh     : rules.perPoLow;
    28→  return showUps * visitRate + (workedSecs / 3600) * rules.hourlyRate + deposits * poRate;
    29→}
    30→
    31→function prevMonth(year: number, month: number): [number, number] {
    32→  return month === 1 ? [year - 1, 12] : [year, month - 1];
    33→}
    34→function nextMonth(year: number, month: number): [number, number] {
    35→  return month === 12 ? [year + 1, 1] : [year, month + 1];
    36→}
