    21→// SQL fragment: completed seconds for sessions started today (Moscow time).
    22→// Only counts sessions with ended_at IS NOT NULL — open/stale sessions are excluded.
    23→const TODAY_PRIOR_SQL = `
    24→  SELECT COALESCE(SUM(
    25→    LEAST(GREATEST(0,
    26→      EXTRACT(EPOCH FROM (ended_at - started_at))::INT - total_break_secs
    27→    ), $2)
    28→  ), 0) AS prior_secs
    29→  FROM work_sessions
    30→  WHERE manager_name = $1
    31→    AND ended_at IS NOT NULL
    32→    AND (started_at AT TIME ZONE 'Europe/Moscow')::DATE
    33→        = (NOW() AT TIME ZONE 'Europe/Moscow')::DATE
    34→`;
    35→
    36→// Close stale open sessions from PREVIOUS days with zero duration
    37→// so they don't pollute today's stats.
    38→const CLOSE_STALE_PREV_DAYS_SQL = `
    39→  UPDATE work_sessions
    40→  SET ended_at = started_at
    41→  WHERE manager_name = $1
    42→    AND ended_at IS NULL
    43→    AND (started_at AT TIME ZONE 'Europe/Moscow')::DATE
    44→        < (NOW() AT TIME ZONE 'Europe/Moscow')::DATE
